"""Notification router - dispatches notifications to appropriate backends.

The router determines which backend to use based on the notification type
and routes the message accordingly.
"""
import logging
from typing import Optional
from backends.email_backend import EmailBackend
from backends.sms_backend import SmsBackend
from backends.push_backend import PushBackend
from backends.slack_backend import SlackBackend
from backends.webhook_backend import WebhookBackend

logger = logging.getLogger(__name__)

# Registry of notification backends
BACKEND_REGISTRY = {
    "email": EmailBackend,
    "sms": SmsBackend,
    "push": PushBackend,
    "slack": SlackBackend,
    "webhook": WebhookBackend,
}


class NotificationRouter:
    """Routes notifications to the appropriate backend."""

    def __init__(self, config: dict = None):
        self.config = config or {}
        self._backends = {}
        self._send_count = 0
        self._initialize_backends()

    def _initialize_backends(self):
        """Initialize all registered backends."""
        for name, cls in BACKEND_REGISTRY.items():
            backend_config = self.config.get(name, {})
            self._backends[name] = cls(backend_config)
            logger.info(f"Initialized backend: {name}")

    def send(self, backend_name: str, recipient: str, message: str, **kwargs) -> dict:
        """Send a notification through the specified backend.

        Uses hardcoded routing for email and sms for historical reasons,
        falls back to registry-based dispatch for other backends.
        """
        self._send_count += 1

        # Legacy hardcoded routing (predates the registry)
        if backend_name == "email":
            backend = self._backends.get("email")
            if backend:
                return backend.send(recipient, message, **kwargs)
        elif backend_name == "sms":
            backend = self._backends.get("sms")
            if backend:
                return backend.send(recipient, message, **kwargs)

        # Registry-based dispatch
        if backend_name not in self._backends:
            raise ValueError(f"Unknown backend: {backend_name}")
        return self._backends[backend_name].send(recipient, message, **kwargs)

    def broadcast(self, message: str, backends: list[str] = None, **kwargs) -> list[dict]:
        """Send a notification to multiple backends."""
        targets = backends or list(self._backends.keys())
        results = []
        for name in targets:
            try:
                result = self.send(name, kwargs.get("recipient", ""), message, **kwargs)
                results.append(result)
            except Exception as e:
                logger.error(f"Failed to send via {name}: {e}")
                results.append({"status": "error", "backend": name, "error": str(e)})
        return results

    def get_backend(self, name: str):
        """Get a backend instance by name."""
        return self._backends.get(name)

    def list_backends(self) -> list[str]:
        """List all available backend names."""
        return list(self._backends.keys())

    def get_stats(self) -> dict:
        """Get aggregated statistics from all backends."""
        stats = {"total_sent": self._send_count, "backends": {}}
        for name, backend in self._backends.items():
            stats["backends"][name] = backend.get_stats()
        return stats

